<script>
    document.addEventListener('DOMContentLoaded', function() {
        // ----------------text-to-copy----------------------------------------
        const buttons = document.querySelectorAll('.copy-code-btn');

        buttons.forEach(button => {
            button.addEventListener('click', function(e) {
                e.preventDefault();

                const code = this.getAttribute('data-code');
                const span = this.querySelector('span');
                const originalText = span.textContent;

                // Метод 1: Современный Clipboard API
                if (navigator.clipboard && navigator.clipboard.writeText) {
                    navigator.clipboard.writeText(code).then(() => {
                        span.textContent = '✓ Скопировано!';
                        setTimeout(() => {
                            span.textContent = originalText;
                        }, 1500);
                    }).catch(err => {
                        console.error('Clipboard API ошибка:', err);
                        fallbackCopyText(code, span, originalText);
                    });
                } else {
                    // Метод 2: Альтернативный метод для старых браузеров
                    fallbackCopyText(code, span, originalText);
                }
            });
        });

        // Альтернативный метод копирования
        function fallbackCopyText(text, span, originalText) {
            const textarea = document.createElement('textarea');
            textarea.value = text;
            textarea.style.position = 'fixed';
            textarea.style.top = '-9999px';
            textarea.style.left = '-9999px';
            document.body.appendChild(textarea);
            textarea.select();
            textarea.setSelectionRange(0, text.length);

            try {
                const success = document.execCommand('copy');
                if (success) {
                    span.textContent = '✓ Скопировано!';
                    setTimeout(() => {
                        span.textContent = originalText;
                    }, 1500);
                } else {
                    span.textContent = '❌ Ошибка';
                    setTimeout(() => {
                        span.textContent = originalText;
                    }, 1500);
                }
            } catch (err) {
                console.error('Fallback ошибка:', err);
                span.textContent = '❌ Ошибка';
                setTimeout(() => {
                    span.textContent = originalText;
                }, 1500);
            }

            document.body.removeChild(textarea);
        }

        // ------------------shor-more-reviews------------------------
        const showMoreBtn = document.getElementById('show-more-btn');
        const reviewsList = document.getElementById('reviews-list');
        const reviews = reviewsList ? Array.from(reviewsList.children) : [];
        let visibleCount = 1;

        // Скрываем все отзывы кроме первого
        for (let i = 1; i < reviews.length; i++) {
            reviews[i].classList.add('hidden-review');
        }

        if (showMoreBtn && reviews.length > 1) {
            showMoreBtn.addEventListener('click', function() {
                let newVisibleCount = visibleCount + 3;

                for (let i = visibleCount; i < newVisibleCount && i < reviews.length; i++) {
                    reviews[i].classList.remove('hidden-review');
                }

                visibleCount = newVisibleCount;

                if (visibleCount >= reviews.length) {
                    showMoreBtn.style.display = 'none';
                } else {
                    showMoreBtn.textContent = `Показать еще`;
                }
            });
        }
    });
</script>
